-- CorteQS Blog Modülü — Faz 1
-- Yeni tablo: blog_posts (ülke/kategori bazlı rehber yazıları)
-- İçerik markdown olarak saklanır; public sayfa react-markdown ile render eder.
-- RLS: public yalnız published=true SELECT; yazma is_admin(auth.uid()) ile sınırlı.
-- NOT: admin_users tablosu kaldırıldı (mig 20260609003000) — kontrol is_admin() RPC.
-- Seed: 10 ülke × 3 kategori = 30 yazı, "cortqs blog deep-research-report.md" kaynağından
--       (cite kaynak işaretleri ve mermaid blokları temizlenerek) aktarıldı.

BEGIN;

CREATE TABLE IF NOT EXISTS public.blog_posts (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  slug            TEXT        NOT NULL UNIQUE,
  title           TEXT        NOT NULL,
  excerpt         TEXT        NOT NULL DEFAULT $$$$,
  content_markdown TEXT       NOT NULL DEFAULT $$$$,
  country         TEXT        NOT NULL DEFAULT $$$$,
  country_label   TEXT        NOT NULL DEFAULT $$$$,
  category        TEXT        NOT NULL DEFAULT $$genel$$
                    CHECK (category IN ($$giris-ulasim$$, $$gundelik-butce$$, $$kultur-sosyal$$, $$genel$$)),
  category_label  TEXT        NOT NULL DEFAULT $$$$,
  cover_image     TEXT,
  published       BOOLEAN     NOT NULL DEFAULT false,
  published_at    TIMESTAMPTZ,
  sort_order      INTEGER     NOT NULL DEFAULT 0,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS blog_posts_published_idx ON public.blog_posts (published, sort_order);
CREATE INDEX IF NOT EXISTS blog_posts_country_idx   ON public.blog_posts (country);
CREATE INDEX IF NOT EXISTS blog_posts_category_idx  ON public.blog_posts (category);

CREATE OR REPLACE FUNCTION public.touch_blog_posts_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $fn$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$fn$;

DROP TRIGGER IF EXISTS trg_blog_posts_updated_at ON public.blog_posts;
CREATE TRIGGER trg_blog_posts_updated_at
  BEFORE UPDATE ON public.blog_posts
  FOR EACH ROW EXECUTE FUNCTION public.touch_blog_posts_updated_at();

ALTER TABLE public.blog_posts ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Blog posts: public read published"
  ON public.blog_posts FOR SELECT TO anon, authenticated
  USING (published = true);

CREATE POLICY "Blog posts: admin read all"
  ON public.blog_posts FOR SELECT TO authenticated
  USING (public.is_admin(auth.uid()));

CREATE POLICY "Blog posts: admin insert"
  ON public.blog_posts FOR INSERT TO authenticated
  WITH CHECK (public.is_admin(auth.uid()));

CREATE POLICY "Blog posts: admin update"
  ON public.blog_posts FOR UPDATE TO authenticated
  USING (public.is_admin(auth.uid()))
  WITH CHECK (public.is_admin(auth.uid()));

CREATE POLICY "Blog posts: admin delete"
  ON public.blog_posts FOR DELETE TO authenticated
  USING (public.is_admin(auth.uid()));

